import React from 'react';
import { CardContainer, CardBody, CardItem } from './ui/3d-card';

const TaskCard = ({ task, currentUser, onPosterClick, onAccept, accepting }) => {
  const acceptedIds = (task.acceptedHustlers || []).map(u => u.id);
  const hasAccepted = currentUser && acceptedIds.includes(currentUser.id);
  const date = task.createdAt ? new Date(task.createdAt) : null;
  const formattedDate = date ? date.toLocaleDateString('en-US', { 
    year: 'numeric', 
    month: 'short', 
    day: 'numeric' 
  }) : '';

  const imageUrl = task.imageUrl || 'https://images.unsplash.com/photo-1464983953574-0892a716854b?auto=format&fit=crop&w=400&q=80';
  const profilePicUrl = (task.poster?.profilePicUrl?.startsWith('/') 
    ? `http://localhost:8080${task.poster.profilePicUrl}` 
    : (task.poster?.profilePicUrl || `https://ui-avatars.com/api/?name=${task.poster?.username || 'U'}`));

  return (
    <CardContainer className="w-full h-full">
      <CardBody className="bg-gray-50 relative group/card dark:hover:shadow-2xl dark:hover:shadow-emerald-500/[0.1] dark:bg-black dark:border-white/[0.2] border-black/[0.1] w-full h-full rounded-xl p-6 border flex flex-col">
        <div className="flex items-center justify-between w-full">
          <CardItem
            translateZ="20"
            className="text-sm text-gray-400"
          >
            {formattedDate}
          </CardItem>
          <CardItem
            translateZ="20"
            className="px-2 py-1 text-xs font-medium rounded-full" 
            style={{ 
              backgroundColor: task.status === 'OPEN' ? '#DCFCE7' : '#FEE2E2',
              color: task.status === 'OPEN' ? '#166534' : '#991B1B'
            }}
          >
            {task.status}
          </CardItem>
        </div>

        <div className="flex items-center gap-3 mt-4">
          <CardItem translateZ="30">
            <img
              src={profilePicUrl}
              alt={task.poster?.username || 'User'}
              className="rounded-full w-10 h-10 object-cover border-2 border-white cursor-pointer hover:brightness-90 transition"
              onClick={() => onPosterClick(task.poster?.username)}
            />
          </CardItem>
          <CardItem translateZ="30">
            <p className="text-sm text-gray-400">Posted by</p>
            <p className="font-medium text-gray-800 dark:text-white">{task.poster?.username || 'Unknown'}</p>
          </CardItem>
        </div>

        <CardItem 
          translateZ="40"
          className="text-xl font-bold mt-4 mb-2 text-gray-800 dark:text-white line-clamp-2"
        >
          {task.title}
        </CardItem>

        <div className="flex-1">
          <CardItem 
            translateZ="50"
            className="w-full mt-4 h-40 overflow-hidden rounded-lg"
          >
            <img 
              src={imageUrl} 
              alt={task.title} 
              className="w-full h-full object-cover group-hover/card:scale-105 transition-transform duration-300"
            />
          </CardItem>

          <CardItem
            as="p"
            translateZ="40"
            className="text-gray-600 dark:text-gray-300 text-sm mt-3 line-clamp-3"
          >
            {task.description}
          </CardItem>

          {task.tags && (
            <CardItem 
              translateZ="30"
              className="mt-3 flex flex-wrap gap-2"
            >
              {task.tags.split(',').map((tag, index) => (
                <span 
                  key={index} 
                  className="px-2 py-1 text-xs bg-gray-100 dark:bg-gray-800 rounded-full text-gray-600 dark:text-gray-300"
                >
                  {tag.trim()}
                </span>
              ))}
            </CardItem>
          )}
        </div>

        <div className="flex items-center justify-between mt-6">
          <CardItem
            translateZ="40"
            as="div"
            className="text-lg font-bold text-indigo-600 dark:text-indigo-400"
          >
            ${task.budget?.toLocaleString() || '0'}
          </CardItem>

          {currentUser?.role === 'HUSTLER' && (
            <CardItem translateZ="50">
              <button
                onClick={() => onAccept(task.id)}
                disabled={hasAccepted || accepting === task.id}
                className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
                  hasAccepted 
                    ? 'bg-green-100 text-green-800 cursor-default' 
                    : 'bg-indigo-600 text-white hover:bg-indigo-700'
                }`}
              >
                {hasAccepted ? 'Accepted' : (accepting === task.id ? 'Processing...' : 'Accept Task')}
              </button>
            </CardItem>
          )}
        </div>
      </CardBody>
    </CardContainer>
  );
};

export default TaskCard;
